  ?message tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_55e03d8a_7ec7_4221_a353_afe03bfcd155> .
  OPTIONAL { ?message bbo:name ?messageName . }
  OPTIONAL { ?message bbo:id ?messageId . }
}
